#!/usr/bin/env node
/**
 * PreToolUse Hook: Codex Bash Guard
 *
 * Intercepts `codex-companion.mjs task` Bash calls made by the codex-rescue
 * agent and validates the command shape before execution.
 *
 *   Guard 1 — Block unknown flags instead of rewriting them.
 *             Command generation must come from the shared codex handoff
 *             runtime, not from implicit hook-side repair logic.
 *
 *   Guard 2 — Require --prompt-file and reject inline positional prompts.
 *             Foreground /plan handoffs should arrive as explicit prompt-file
 *             commands generated by scripts/lib/codex-handoff.js.
 *
 *   Guard 3 — Block --background for domain-scoped delegation.
 *             Domain handoffs are foreground-only in the automatic /plan flow.
 *
 *   Guard 4 — Block a second codex-companion invocation for the same domain within
 *            the same session. codex-rescue enters a retry loop when the first
 *            call fails; the hook detects per-domain session-scoped state and
 *            exits with code 2 to block the duplicate call and surface a clear
 *            error message. Different domains may each be invoked once (required
 *            for parallel multi-domain plans).
 *
 * Trigger: PreToolUse on Bash
 * Profile: standard,strict
 * Exit 0  → pass-through
 * Exit 2  → block tool execution
 *
 * Known-valid flags (from codex-companion.mjs source):
 *   boolean : json, write, resume-last, resume, fresh, background
 *   value   : model, effort, cwd, prompt-file, output-format
 */

'use strict';

const fs = require('fs');
const path = require('path');
const os = require('os');
const crypto = require('crypto');

// ---- Session state helpers (same pattern as constraint-guard.js) ----

function getSessionKey() {
  if (process.env.CLAUDE_SESSION_ID) return process.env.CLAUDE_SESSION_ID;
  return crypto.createHash('sha1').update(process.cwd()).digest('hex').slice(0, 12);
}

function getStatePath() {
  return path.join(os.tmpdir(), `ecc-codex-guard-${getSessionKey()}.json`);
}

function loadState() {
  try {
    return JSON.parse(fs.readFileSync(getStatePath(), 'utf8'));
  } catch {
    return { domains: {} };
  }
}

function saveState(state) {
  try {
    fs.writeFileSync(getStatePath(), JSON.stringify(state), 'utf8');
  } catch { /* never block on state save failure */ }
}

// ---- Command parsing ----

/**
 * Known valid flags for codex-companion.mjs.
 * Source: booleanOptions + valueOptions in codex-companion.mjs.
 */
const BOOLEAN_FLAGS = new Set([
  'json', 'write', 'resume-last', 'resume', 'fresh', 'background',
]);
const VALUE_FLAGS = new Set([
  'model', 'effort', 'cwd', 'prompt-file', 'output-format',
]);

/**
 * Guard-internal flag: allowed for validation purposes but still treated as
 * semantically meaningful by the guard.
 */
const INTERNAL_VALUE_FLAGS = new Set([
  'domain-id',
]);

/**
 * Minimal argv tokeniser — handles quoted strings and --flag=value forms.
 * Returns array of tokens preserving quotes stripped.
 */
function tokenise(cmd) {
  const tokens = [];
  let current = '';
  let inSingle = false;
  let inDouble = false;

  for (let i = 0; i < cmd.length; i++) {
    const ch = cmd[i];
    if (ch === "'" && !inDouble) { inSingle = !inSingle; continue; }
    if (ch === '"' && !inSingle) { inDouble = !inDouble; continue; }
    if ((ch === ' ' || ch === '\t') && !inSingle && !inDouble) {
      if (current.length) { tokens.push(current); current = ''; }
    } else {
      current += ch;
    }
  }
  if (current.length) tokens.push(current);
  return tokens;
}

/**
 * Detect whether the command is a codex-companion.mjs task invocation.
 * Matches: node "…/codex-companion.mjs" task …
 *          node '…/codex-companion.mjs' task …
 */
function isCodexCompanionTaskCall(command) {
  return /codex-companion\.mjs/.test(command) &&
    /\btask\b/.test(command);
}

/**
 * Parse a codex-companion.mjs task invocation into:
 *   { prefix, flags, inlinePrompt }
 *
 * prefix       — everything up to and including "task"
 * flags        — array of { key, value, raw } for flags after "task"
 * inlinePrompt — the positional argument (if any) that is not a flag
 *
 * Returns null if parsing fails.
 */
function parseCompanionCall(command) {
  const tokens = tokenise(command);

  // Find the index of "task" (the subcommand)
  const taskIdx = tokens.findIndex(t => t === 'task');
  if (taskIdx === -1) return null;

  const prefix = tokens.slice(0, taskIdx + 1).join(' ');
  const rest = tokens.slice(taskIdx + 1);

  const flags = [];
  let inlinePrompt = null;
  let i = 0;

  while (i < rest.length) {
    const tok = rest[i];

    if (tok.startsWith('--')) {
      // --key=value or --key value or --boolean-flag
      const eqIdx = tok.indexOf('=');
      if (eqIdx !== -1) {
        const key = tok.slice(2, eqIdx);
        const value = tok.slice(eqIdx + 1);
        flags.push({ key, value, raw: tok });
        i++;
      } else {
        const key = tok.slice(2);
        if ((VALUE_FLAGS.has(key) || INTERNAL_VALUE_FLAGS.has(key)) && i + 1 < rest.length && !rest[i + 1].startsWith('--')) {
          flags.push({ key, value: rest[i + 1], raw: `${tok} ${rest[i + 1]}` });
          i += 2;
        } else {
          flags.push({ key, value: null, raw: tok });
          i++;
        }
      }
    } else {
      // Positional argument — the task prompt
      if (inlinePrompt === null) {
        inlinePrompt = tok;
      }
      i++;
    }
  }

  return { prefix, flags, inlinePrompt };
}

/**
 * Returns the first matching flag object, if present.
 */
function getFlag(flags, key) {
  return flags.find(flag => flag.key === key) || null;
}

function block(messageLines) {
  process.stderr.write(`\n[CodexGuard] BLOCKED: ${messageLines.join('\n')}\n\n`);
  return { exitCode: 2 };
}

// ---- Main ----

function run(rawInput) {
  let input;
  try {
    input = JSON.parse(rawInput);
  } catch {
    return rawInput;
  }

  const command = input.tool_input?.command;
  if (typeof command !== 'string') return rawInput;

  if (!isCodexCompanionTaskCall(command)) return rawInput;

  // ---- Fix 4: block duplicate invocations per domain within the same session ----
  const parsed = parseCompanionCall(command);
  if (!parsed) return rawInput;

  const invalidFlags = parsed.flags
    .filter(flag => !BOOLEAN_FLAGS.has(flag.key) && !VALUE_FLAGS.has(flag.key) && !INTERNAL_VALUE_FLAGS.has(flag.key))
    .map(flag => `--${flag.key}`);
  if (invalidFlags.length > 0) {
    return block([
      `Unknown codex-companion flags: ${invalidFlags.join(', ')}`,
      'Generate the command via scripts/lib/codex-handoff.js instead of relying on hook-side rewriting.',
    ]);
  }

  if (parsed.inlinePrompt && parsed.inlinePrompt.trim().length > 0) {
    return block([
      'Inline positional prompts are not allowed.',
      'Write the BRIEF to a file first and pass --prompt-file <path>.',
    ]);
  }

  const promptFileFlag = getFlag(parsed.flags, 'prompt-file');
  if (!promptFileFlag || !promptFileFlag.value) {
    return block([
      'Missing required --prompt-file <path>.',
      'Foreground Codex handoffs must be constructed with an explicit prompt file.',
    ]);
  }

  const domainFlag = parsed.flags.find(f => f.key === 'domain-id');
  const domainKey = (domainFlag && domainFlag.value) ? domainFlag.value : '_default';
  const backgroundFlag = getFlag(parsed.flags, 'background');

  if (domainFlag && backgroundFlag) {
    return block([
      `Domain-scoped delegation for "${domainKey}" cannot use --background.`,
      'Background mode is manual-only. Automatic /plan handoffs must stay foreground.',
    ]);
  }

  const state = loadState();
  if ((state.domains[domainKey] || 0) >= 1) {
    return block([
      `codex-companion.mjs task for domain "${domainKey}" already invoked this session.`,
      'A second call indicates the first failed and codex-rescue entered a retry loop.',
      'Fix the BRIEF or prompt content before retrying.',
    ]);
  }

  // Record this invocation (per domain)
  state.domains = state.domains || {};
  state.domains[domainKey] = (state.domains[domainKey] || 0) + 1;
  saveState(state);

  return rawInput;
}

module.exports = { run };

// Allow direct execution for testing
if (require.main === module) {
  const chunks = [];
  process.stdin.on('data', d => chunks.push(d));
  process.stdin.on('end', () => {
    const raw = Buffer.concat(chunks).toString('utf8');
    const result = run(raw);
    if (typeof result === 'string') {
      process.stdout.write(result);
    } else if (result && typeof result === 'object') {
      if (result.exitCode === 2) {
        process.exit(2);
      }
    } else {
      process.stdout.write(raw);
    }
    process.exit(0);
  });
}
